#!/usr/bin/env node
/**
 * Build resources/sample-paper.pdf — a short, research-looking workshop
 * paper users load from the welcome card to try Fathom without needing
 * their own PDF. Three pages: a real-feeling abstract + methodology +
 * results structure, two real figures (architecture diagram + results
 * chart, generated by build-sample-figures.mjs and embedded here as
 * PNGs), and a references section with citation markers so the lens has
 * something to resolve with Grep.
 *
 * We stay away from real copyrighted papers for redistribution cleanliness
 * — the content is fictitious but deliberately written in the register
 * of a short ML / systems paper so the reader's pinch produces
 * meaty explanations.
 */

import { PDFDocument, StandardFonts, rgb } from 'pdf-lib';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';
import { writeFile, readFile } from 'node:fs/promises';

const __dirname = dirname(fileURLToPath(import.meta.url));
const res = (name) => join(__dirname, '..', 'resources', name);
const out = res('sample-paper.pdf');

const doc = await PDFDocument.create();
doc.setTitle('Filesystem-First Grounding for LLM Readers');
doc.setAuthor('Ashrya, et al.');
doc.setSubject('Fathom sample paper');
doc.setCreator('scripts/build-sample-pdf.mjs');

const serif = await doc.embedFont(StandardFonts.TimesRoman);
const serifBold = await doc.embedFont(StandardFonts.TimesRomanBold);
const serifItalic = await doc.embedFont(StandardFonts.TimesRomanItalic);

// Embed the two PNG figures produced by build-sample-figures.mjs.
const figArchBytes = await readFile(res('sample-fig-architecture.png'));
const figResultsBytes = await readFile(res('sample-fig-results.png'));
const figArch = await doc.embedPng(figArchBytes);
const figResults = await doc.embedPng(figResultsBytes);

// Letter at 72dpi
const PAGE_W = 612;
const PAGE_H = 792;
const M = 62;
const CONTENT_W = PAGE_W - 2 * M;
const ink = rgb(0.1, 0.08, 0.07);
const rule = rgb(0.6, 0.55, 0.4);
const amber = rgb(0.79, 0.51, 0.17);

function wrap(text, font, size, maxWidth) {
  const words = text.split(/\s+/);
  const lines = [];
  let line = '';
  for (const w of words) {
    const trial = line ? `${line} ${w}` : w;
    if (font.widthOfTextAtSize(trial, size) > maxWidth && line) {
      lines.push(line);
      line = w;
    } else {
      line = trial;
    }
  }
  if (line) lines.push(line);
  return lines;
}

/** Draw a paragraph; returns the next y to resume from. */
function para(page, { text, x, y, width, font, size, leading, color = ink }) {
  const lines = wrap(text, font, size, width);
  let cursor = y;
  for (const line of lines) {
    page.drawText(line, { x, y: cursor, size, font, color });
    cursor -= leading;
  }
  return cursor - 2;
}

function heading(page, { text, x, y, size = 12.5 }) {
  page.drawText(text, { x, y, size, font: serifBold, color: ink });
  return y - size - 6;
}

function footer(page, pageNumber) {
  page.drawText(String(pageNumber), {
    x: PAGE_W / 2 - 4, y: M / 2,
    size: 9, font: serif, color: rule,
  });
}

// ========== PAGE 1 ==========
{
  const page = doc.addPage([PAGE_W, PAGE_H]);
  let y = PAGE_H - M - 6;

  page.drawText('Filesystem-First Grounding for LLM Readers', {
    x: M, y, size: 18, font: serifBold, color: ink,
  });
  y -= 24;

  page.drawText('Ashrya A., Fathom Research', {
    x: M, y, size: 10.5, font: serifItalic, color: ink,
  });
  y -= 14;
  page.drawText('Fathom Workshop on Reading Interfaces, 2026', {
    x: M, y, size: 9.5, font: serif, color: rule,
  });
  y -= 20;
  page.drawLine({ start: { x: M, y }, end: { x: PAGE_W - M, y }, thickness: 0.6, color: rule });
  y -= 22;

  y = heading(page, { text: 'Abstract', y, x: M });
  y = para(page, {
    text:
      'We argue that retrieval-augmented generation (RAG) is the wrong primitive for ' +
      'reading a single research paper with an LLM. Embedding-nearest-neighbour lookup ' +
      'conflates meaning-adjacent spans with factually opposite ones (the self-attention ' +
      'and the "no self-attention" sentence in the same paper both score highly), and ' +
      'the added infrastructure is unjustified at paper scale. We present an alternative: ' +
      'the reader extracts the paper into a small filesystem of files and hands the ' +
      'model its standard shell toolbox (Read, Grep, Glob). Citations resolve by literal ' +
      'match; figures are read by path; the LLM produces answers that cite page numbers ' +
      'a human can click. On 50 ML papers, precision of [N]-style citation resolution ' +
      'improves from 61% (RAG) to 94% (filesystem-first) while mean latency drops by 38%.',
    x: M, y, width: CONTENT_W, font: serif, size: 10.5, leading: 14,
  });

  y -= 10;
  y = heading(page, { text: '1. Introduction', y, x: M });
  y = para(page, {
    text:
      'The practice of reading a research paper alongside a large language model has ' +
      'settled into a familiar loop: the reader hits a dense passage, copies it into a ' +
      'chat window, asks for clarification, asks for clarification of the clarification, ' +
      'and — some minutes later — surfaces to find their position in the source paper ' +
      'irrecoverable. We take the position that the friction lives not in the model but ' +
      'in the substrate through which the model sees the paper. A paper is a small, ' +
      'structured object — tens of kilobytes of text, a handful of figures, a references ' +
      'section. Treating it as a corpus to be embedded, chunked, and vector-searched ' +
      'imposes retrieval overhead on every query while losing the structure that made ' +
      'it easy to search in the first place.',
    x: M, y, width: CONTENT_W, font: serif, size: 10.5, leading: 14,
  });

  y -= 6;
  y = para(page, {
    text:
      'We describe a reader that extracts the paper client-side into a directory of ' +
      'plain files — content.md with page-boundary markers, one PNG per figure — and ' +
      'grants the LLM the same shell toolbox (Read/Grep/Glob) a human would use. ' +
      'Citations like [21] resolve by literal string match into the inline references ' +
      'block; figure-precision lookups are file-reads; there is no nearest-neighbour ' +
      'search in the pipeline. Section 2 describes the extraction; Section 3 reports ' +
      'results on 50 papers from recent ML conferences [21, 34].',
    x: M, y, width: CONTENT_W, font: serif, size: 10.5, leading: 14,
  });

  footer(page, 1);
}

// ========== PAGE 2 ==========
{
  const page = doc.addPage([PAGE_W, PAGE_H]);
  let y = PAGE_H - M - 6;

  y = heading(page, { text: '2. Method', y, x: M });
  y = para(page, {
    text:
      'The extractor is a short pipeline staged inside a Chromium renderer so that no ' +
      'external binaries (poppler, Ghostscript) are required at the reader\'s machine. ' +
      'Each page\'s text-layer is walked in reading order with column-aware gap ' +
      'heuristics: a paragraph is a run of text items whose x-coordinates overlap by ' +
      'at least 35% and whose horizontal gaps do not exceed 3.5 times the dominant ' +
      'glyph width. In parallel, each page\'s PDF operator list is traversed while ' +
      'tracking the current transformation matrix through save/restore/transform ops; ' +
      'every paintImageXObject and inline-image op records an axis-aligned bounding ' +
      'box of its placement on the page. Figures are cropped out of a single ' +
      'canvas-rendered PNG at 2× density; tiny boxes (< 60pt in either dimension) are ' +
      'discarded as likely icons.',
    x: M, y, width: CONTENT_W, font: serif, size: 10.5, leading: 14,
  });

  y -= 6;
  y = para(page, {
    text:
      'The result is a per-paper sidecar folder: content.md (full text, in reading ' +
      'order, with inline figure references), an images/ directory (one PNG per ' +
      'extracted figure), and a single JSON digest produced by a one-shot LLM call ' +
      'over the sidecar. No embedding model is instantiated; no vector store is ' +
      'written. Figure 1 summarises the whole pipeline.',
    x: M, y, width: CONTENT_W, font: serif, size: 10.5, leading: 14,
  });

  // Figure 1
  y -= 18;
  const fig1W = CONTENT_W;
  const fig1H = fig1W * (figArch.height / figArch.width);
  page.drawImage(figArch, { x: M, y: y - fig1H, width: fig1W, height: fig1H });
  y -= fig1H + 6;

  y -= 6;
  y = heading(page, { text: '3. Results', y, x: M });
  y = para(page, {
    text:
      'We evaluate on a benchmark of 50 recently-published ML papers (n = 50, drawn ' +
      'from NeurIPS, ICLR, and ACL 2023–2025 [41, 42, 48]). Each paper is annotated ' +
      'with 10 citation-resolution queries of the form "what does [N] refer to, and ' +
      'what is the claim being cited for?" We compare three systems: a standard RAG ' +
      'pipeline with text-embedding-3-small + BM25 rerank, the same pipeline with an ' +
      'additional cross-encoder reranker over the top-20, and our filesystem-first ' +
      'setup. An answer is marked correct if both the paper identifier and the claim ' +
      'cited are correctly named.',
    x: M, y, width: CONTENT_W, font: serif, size: 10.5, leading: 14,
  });

  footer(page, 2);
}

// ========== PAGE 3 ==========
{
  const page = doc.addPage([PAGE_W, PAGE_H]);
  let y = PAGE_H - M - 6;

  // Figure 2
  const fig2W = CONTENT_W * 0.85;
  const fig2H = fig2W * (figResults.height / figResults.width);
  page.drawImage(figResults, {
    x: M + (CONTENT_W - fig2W) / 2,
    y: y - fig2H,
    width: fig2W,
    height: fig2H,
  });
  y -= fig2H + 12;

  y = para(page, {
    text:
      'Figure 2 summarises the precision results. RAG achieves 61% precision on ' +
      'citation resolution; adding a cross-encoder rerank raises this to 78%; the ' +
      'filesystem-first setup reaches 94%. The remaining 6% failure cases are ' +
      'dominated by papers that cite unpublished work by author-only initials, ' +
      'which cannot be disambiguated by any system without web search. Latency ' +
      'medians (measured per query, warm index): 2.1s for RAG, 3.4s for RAG+rerank, ' +
      '1.3s for filesystem-first; all three include the underlying LLM completion.',
    x: M, y, width: CONTENT_W, font: serif, size: 10.5, leading: 14,
  });

  y -= 12;
  y = heading(page, { text: '4. Discussion', y, x: M });
  y = para(page, {
    text:
      'The result should not be surprising: when the substrate being grounded in is ' +
      'small, structured, and has its own natural index (page numbers, section ' +
      'headings, reference numbers), exact-match tools outperform retrieval-by-' +
      'similarity. The contribution of this paper is therefore less algorithmic than ' +
      'architectural — a reminder that the right primitive for a single-paper reader ' +
      'is the filesystem, not the vector store [27]. Extensions to multi-paper ' +
      'reading libraries are future work; we suspect that filesystem-first grounding ' +
      'composes naturally with cross-paper search through Glob on a user-maintained ' +
      'shelf of paper sidecars.',
    x: M, y, width: CONTENT_W, font: serif, size: 10.5, leading: 14,
  });

  y -= 14;
  y = heading(page, { text: 'References', y, x: M });
  y -= 2;
  const refs = [
    '[21] Vaswani, A., et al. Attention Is All You Need. NeurIPS 2017.',
    '[27] Kernighan, B. W., Plauger, P. J. The Elements of Programming Style. 1978.',
    '[34] Karpukhin, V., et al. Dense Passage Retrieval for Open-Domain QA. EMNLP 2020.',
    '[41] Touvron, H., et al. LLaMA: Open and Efficient Foundation Language Models. 2023.',
    '[42] OpenAI. GPT-4 Technical Report. 2023.',
    '[48] Anthropic. Claude 3 Model Card. 2024.',
  ];
  for (const r of refs) {
    page.drawText(r, { x: M, y, size: 9.5, font: serif, color: ink });
    y -= 12;
  }

  y -= 16;
  page.drawText('—  end  —', {
    x: PAGE_W / 2 - serifItalic.widthOfTextAtSize('—  end  —', 9) / 2,
    y,
    size: 9, font: serifItalic, color: rule,
  });

  // subtle amber accent line at the top of references for the brand
  page.drawLine({ start: { x: M, y: y + 20 }, end: { x: M + 40, y: y + 20 }, thickness: 1, color: amber });

  footer(page, 3);
}

const bytes = await doc.save();
await writeFile(out, bytes);
console.log(`  ✓ ${out} (${bytes.length} bytes)`);
